from pathlib import Path
import json, shutil, os

cwd = Path.cwd()
print(f"cwd={cwd}")

# The prior registration failed because the descriptor was not in this space root.
# First try to locate an existing descriptor from the previous local-build step.
candidates = []
search_roots = [cwd]
for extra in [Path('/home/k/Kernos/.kernos_sandbox'), Path('/tmp')]:
    if extra.exists():
        search_roots.append(extra)

for root in search_roots:
    try:
        for p in root.rglob('flip_coin.tool.json'):
            candidates.append(p)
    except Exception as e:
        print(f"search_skipped={root}: {type(e).__name__}: {e}")

root_descriptor = cwd / 'flip_coin.tool.json'
root_impl = cwd / 'flip_coin.py'

if candidates:
    src = candidates[0]
    if src.resolve() != root_descriptor.resolve():
        shutil.copyfile(src, root_descriptor)
        print(f"copied_descriptor_from={src}")
    else:
        print("descriptor_already_in_space_root")
else:
    # Recreate a minimal local implementation + descriptor in the current space.
    # This is intentionally instance-local workshop material, not a platform change.
    root_impl.write_text(
        "import random\n\n"
        "def run(args=None):\n"
        "    return {\"result\": random.choice([\"heads\", \"tails\"])}\n\n"
        "if __name__ == '__main__':\n"
        "    print(run())\n",
        encoding='utf-8'
    )
    descriptor = {
        "name": "flip_coin",
        "description": "Flip a fair coin and return heads or tails.",
        "input_schema": {
            "type": "object",
            "properties": {},
            "additionalProperties": False
        },
        "implementation": {
            "type": "python",
            "file": "flip_coin.py",
            "entrypoint": "run"
        }
    }
    root_descriptor.write_text(json.dumps(descriptor, indent=2) + "\n", encoding='utf-8')
    print("created_descriptor_and_impl_in_space_root")

print("space_root_files=")
for p in sorted(cwd.iterdir()):
    if p.is_file() and (p.name.startswith('flip_coin') or p.name == 'selftest.txt'):
        print(f"- {p.name} ({p.stat().st_size} bytes)")

print("descriptor_contents=")
print(root_descriptor.read_text(encoding='utf-8'))
